  1→import type { StateHandler, RunContext, RunState } from "../types.js";
  2→import type { StateHandlerMap } from "./engine.js";
  3→import type { GitAdapter } from "../adapters/git.js";
  4→import type { GitHubAdapter } from "../adapters/github.js";
  5→import { runPlanner } from "../agents/planner.js";
  6→import { runImplementer } from "../agents/implementer.js";
  7→import { runReviewer } from "../agents/reviewer.js";
  8→import { runFixer } from "../agents/fixer.js";
  9→import type { Logger } from "../util/logger.js";
 10→import type { DocumenterInput } from "../agents/documenter.js";
 11→import { parseIssueConfig, type ResolvedConfig } from "../config/issue-config.js";
 12→import type { IssueConfig } from "../config/issue-config.js";
 13→import { mergeConfigs } from "../config/merge-config.js";
 14→import { buildResolvedConfigBlock, upsertAidevBlock } from "../config/serialize-config.js";
 15→import type { SkippableState } from "../types.js";
 16→import type { Issue, PullRequest } from "../adapters/github.js";
 17→
 18→export interface Deps {
 19→  git: GitAdapter;
 20→  github: GitHubAdapter;
 21→  logger: Logger;
 22→  runDocumenter: (input: DocumenterInput, logger: Logger) => Promise<void>;
 23→  loadRepoConfig: (cwd: string) => Promise<Partial<IssueConfig>>;
 24→}
 25→
 26→function transition(
 27→  ctx: RunContext,
 28→  nextState: RunState,
 29→  patch?: Partial<RunContext>
 30→) {
 31→  return { nextState, ctx: { ...ctx, ...patch, state: nextState } };
 32→}
 33→
 34→function shouldAutoMerge(ctx: RunContext): boolean {
 35→  return ctx.autoMerge || ctx.issueLabels.includes("auto-merge");
 36→}
 37→
 38→function toPlanningTarget(workItem: Issue | PullRequest): Issue {
 39→  return {
 40→    number: workItem.number,
 41→    title: workItem.title,
 42→    body: workItem.body,
 43→    labels: "labels" in workItem ? workItem.labels : [],
 44→    author: workItem.author,
 45→  };
 46→}
 47→
 48→export function createStateHandlers(deps: Deps): StateHandlerMap {
 49→  const { git, github, logger, runDocumenter, loadRepoConfig } = deps;
 50→
 51→  const init: StateHandler = async (ctx) => {
 52→    if (ctx.targetKind === "pr") {
 53→      const pr = await github.getPr(ctx.prNumber!);
 54→      logger.info("Fetched PR", {
 55→        number: pr.number,
 56→        title: pr.title,
 57→      });
 58→
 59→      if (!ctx.skipAuthorCheck) {
 60→        const authenticatedUser = await github.getAuthenticatedUser();
 61→        if (pr.author !== authenticatedUser) {
 62→          throw new Error(
 63→            `PR #${pr.number} was created by '${pr.author}', not by the authenticated user '${authenticatedUser}'. Use --allow-foreign-issues to bypass this check.`
 64→          );
 65→        }
 66→      }
 67→
 68→      const patch: Partial<RunContext> = {
 69→        issueLabels: [],
 70→        issueTitle: pr.title,
 71→        base: ctx._cliExplicit?.has("base") ? ctx.base : pr.baseRefName,
 72→        branch: pr.headRefName,
 73→        headBranch: pr.headRefName,
 74→      };
 75→
 76→      const mergedCtx = { ...ctx, ...patch };
 77→      await git.createBranch(
 78→        mergedCtx.branch,
 79→        `origin/${pr.headRefName}`,
 80→        mergedCtx.cwd
 81→      );
 82→      logger.info("Checked out PR head branch", {
 83→        branch: mergedCtx.branch,
 84→        base: mergedCtx.base,
 85→      });
 86→      return transition(mergedCtx, "planning");
 87→    }
 88→
 89→    const issue = await github.getIssue(ctx.issueNumber!);
 90→    logger.info("Fetched issue", {
 91→      number: issue.number,
 92→      title: issue.title,
 93→    });
 94→
 95→    if (!ctx.skipAuthorCheck) {
 96→      const authenticatedUser = await github.getAuthenticatedUser();
 97→      if (issue.author !== authenticatedUser) {
 98→        throw new Error(
 99→          `Issue #${issue.number} was created by '${issue.author}', not by the authenticated user '${authenticatedUser}'. Use --allow-foreign-issues to bypass this check.`
100→        );
101→      }
102→    }
103→
104→    // Load repo-level config (.aidev.yml)
105→    const repoConfig = await loadRepoConfig(ctx.cwd);
106→    if (Object.keys(repoConfig).length > 0) {
107→      logger.info("Loaded repo config", { repoConfig });
108→    }
109→
110→    // Parse issue config from body
111→    const issueConfig = parseIssueConfig(issue.body);
112→    if (Object.keys(issueConfig).length > 0) {
113→      logger.info("Parsed issue config", { issueConfig });
114→    }
115→
116→    // Merge: repo < issue, excluding CLI-explicit fields
117→    const cliExplicit = ctx._cliExplicit ?? new Set<string>();
118→    const merged = mergeConfigs(repoConfig, issueConfig, cliExplicit);
119→
120→    const patch: Partial<RunContext> = {
121→      issueLabels: issue.labels,
122→      issueTitle: issue.title,
123→    };
124→
125→    if (merged.maxFixAttempts !== undefined) patch.maxFixAttempts = merged.maxFixAttempts;
126→    if (merged.autoMerge !== undefined) patch.autoMerge = merged.autoMerge;
127→    if (merged.dryRun !== undefined) patch.dryRun = merged.dryRun;
128→    if (merged.base !== undefined) patch.base = merged.base;
129→    if (merged.skip) patch.skipStates = merged.skip as SkippableState[];
130→
131→    const mergedCtx = { ...ctx, ...patch };
132→
133→    // Build resolved config and write back to issue body
134→    const resolvedConfig: ResolvedConfig = {
135→      maxFixAttempts: mergedCtx.maxFixAttempts,
136→      autoMerge: mergedCtx.autoMerge,
137→      dryRun: mergedCtx.dryRun,
138→      base: mergedCtx.base,
139→      skip: (mergedCtx.skipStates ?? []) as SkippableState[],
140→    };
141→    const configBlock = buildResolvedConfigBlock(resolvedConfig);
142→    const updatedBody = upsertAidevBlock(issue.body, configBlock);
143→    await github.updateIssueBody(issue.number, updatedBody);
144→
145→    await git.createBranch(mergedCtx.branch, mergedCtx.base, mergedCtx.cwd);
146→    logger.info("Created branch", { branch: mergedCtx.branch });
147→    return transition(mergedCtx, "planning");
148→  };
149→
150→  const planning: StateHandler = async (ctx) => {
151→    const workItem =
152→      ctx.targetKind === "pr"
153→        ? toPlanningTarget(await github.getPr(ctx.prNumber!))
154→        : await github.getIssue(ctx.issueNumber!);
155→    const planStart = performance.now();
156→    const plan = await runPlanner({ issue: workItem, cwd: ctx.cwd }, logger);
157→    const planElapsed = Math.round(performance.now() - planStart);
158→    logger.info("Plan created", { summary: plan.summary, agentElapsedMs: planElapsed });
159→
160→    if (plan.investigation) {
161→      const comment = `## 🔍 Investigation\n\n${plan.investigation}\n\n## Plan\n\n${plan.steps.map((s, i) => `${i + 1}. ${s}`).join("\n")}`;
162→      if (ctx.targetKind === "pr") {
163→        await github.commentOnPr(ctx.prNumber!, comment);
164→        logger.info("Posted investigation to PR", { pr: ctx.prNumber });
165→      } else {
166→        await github.commentOnIssue(ctx.issueNumber!, comment);
167→        logger.info("Posted investigation to issue", { issue: ctx.issueNumber });
168→      }
169→    }
170→
171→    return transition(ctx, "implementing", { plan });
172→  };
173→
174→  const implementing: StateHandler = async (ctx) => {
175→    if (!ctx.plan) throw new Error("No plan available");
176→    const implStart = performance.now();
177→    const result = await runImplementer(
178→      {
179→        plan: ctx.plan,
180→        workItemKind: ctx.targetKind,
181→        workItemNumber: ctx.targetKind === "pr" ? ctx.prNumber! : ctx.issueNumber!,
182→        cwd: ctx.cwd,
183→      },
184→      logger
185→    );
186→    const implElapsed = Math.round(performance.now() - implStart);
187→    logger.info("Implementation complete", {
188→      changedFiles: result.changedFiles,
189→      agentElapsedMs: implElapsed,
190→    });
191→    return transition(ctx, "reviewing", { result });
192→  };
193→
194→  const reviewing: StateHandler = async (ctx) => {
195→    if (ctx.skipStates?.includes("reviewing")) {
196→      logger.info("Skipping reviewing (configured in issue)");
197→      return transition(ctx, "committing");
198→    }
199→    if (!ctx.plan) throw new Error("No plan available");
200→    const diff = await git.diff(ctx.base, ctx.cwd);
201→    const reviewStart = performance.now();
202→    const review = await runReviewer(
203→      { plan: ctx.plan, diff, cwd: ctx.cwd },
204→      logger
205→    );
206→    const reviewElapsed = Math.round(performance.now() - reviewStart);
207→    logger.info("Review complete", { decision: review.decision, agentElapsedMs: reviewElapsed });
208→
209→    if (review.decision === "changes_requested") {
210→      return transition(ctx, "implementing", { review });
211→    }
212→    return transition(ctx, "committing", { review });
213→  };
214→
215→  const committing: StateHandler = async (ctx) => {
216→    if (!ctx.result) throw new Error("No result available");
217→    if (ctx.skipStates?.includes("documenter")) {
218→      logger.info("Skipping documenter (configured in issue)");
219→    } else {
220→      await runDocumenter({ result: ctx.result, cwd: ctx.cwd }, logger);
221→    }
222→    logger.info("Documentation check completed");
223→    await git.addAll(ctx.cwd);
224→    await git.commit(ctx.result.commitMessageDraft, ctx.cwd);
225→    logger.info("Committed changes");
226→
227→    if (ctx.dryRun) {
228→      logger.info("Dry run - skipping push and PR creation");
229→      return transition(ctx, "done");
230→    }
231→    return transition(ctx, "creating_pr");
232→  };
233→
234→  const creating_pr: StateHandler = async (ctx) => {
235→    if (!ctx.result) throw new Error("No result available");
236→    if (ctx.targetKind === "pr") {
237→      await git.push(ctx.headBranch ?? ctx.branch, ctx.cwd);
238→      logger.info("Updated existing PR branch", { prNumber: ctx.prNumber, branch: ctx.headBranch ?? ctx.branch });
239→      return transition(ctx, "watching_ci", { prNumber: ctx.prNumber });
240→    }
241→    await git.push(ctx.branch, ctx.cwd);
242→    const prNumber = await github.createPr({
243→      title: ctx.result.commitMessageDraft.split("\n")[0]!,
244→      body: ctx.result.prBodyDraft,
245→      head: ctx.branch,
246→      base: ctx.base,
247→    });
248→    logger.info("PR created", { prNumber });
249→    return transition(ctx, "watching_ci", { prNumber });
250→  };
251→
252→  const watching_ci: StateHandler = async (ctx) => {
253→    if (!ctx.prNumber) throw new Error("No PR number");
254→    if (ctx.skipStates?.includes("watching_ci")) {
255→      logger.info("Skipping watching_ci (configured in issue)");
256→      if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
257→      return transition(ctx, "merging");
258→    }
259→    const maxWait = 10 * 60 * 1000; // 10 minutes
260→    const pollInterval = 15 * 1000; // 15 seconds
261→    const gracePeriod = 30 * 1000; // 30 seconds for CI check runs to register
262→    const start = Date.now();
263→
264→    while (Date.now() - start < maxWait) {
265→      const status = await github.getCiStatus(ctx.branch);
266→      if (status === "passing") {
267→        logger.info("CI passed");
268→        if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
269→        return transition(ctx, "merging");
270→      }
271→      if (status === "failing") {
272→        logger.warn("CI failed");
273→        if (ctx.fixAttempts >= ctx.maxFixAttempts) {
274→          logger.error("Max fix attempts exceeded");
275→          return transition(ctx, "failed");
276→        }
277→        return transition(ctx, "fixing", {
278→          fixAttempts: ctx.fixAttempts + 1,
279→        });
280→      }
281→      if (status === "no_checks" && Date.now() - start >= gracePeriod) {
282→        logger.info("No CI checks found after grace period, treating as passing");
283→        if (!shouldAutoMerge(ctx)) return transition(ctx, "done");
284→        return transition(ctx, "merging");
285→      }
286→      await new Promise((r) => setTimeout(r, pollInterval));
287→    }
288→
289→    logger.error("CI timed out");
290→    return transition(ctx, "failed");
291→  };
292→
293→  const fixing: StateHandler = async (ctx) => {
294→    if (!ctx.plan) throw new Error("No plan available");
295→    const ciLog = await github.getCheckRunLogs(ctx.branch);
296→    const fixStart = performance.now();
297→    const fix = await runFixer(
298→      { plan: ctx.plan, ciLog, cwd: ctx.cwd },
299→      logger
300→    );
301→    const fixElapsed = Math.round(performance.now() - fixStart);
302→    logger.info("Fix applied", { rootCause: fix.rootCause, agentElapsedMs: fixElapsed });
303→
304→    await git.addAll(ctx.cwd);
305→    await git.commit(`fix: ${fix.rootCause}`, ctx.cwd);
306→    await git.push(ctx.branch, ctx.cwd);
307→    return transition(ctx, "watching_ci", { fix });
308→  };
309→
310→  const merging: StateHandler = async (ctx) => {
311→    if (!ctx.prNumber) throw new Error("No PR number");
312→    await github.mergePr(ctx.prNumber);
313→    logger.info("PR merged", { prNumber: ctx.prNumber });
314→    return transition(ctx, "closing_issue");
315→  };
316→
317→  const closing_issue: StateHandler = async (ctx) => {
318→    if (ctx.targetKind === "pr") {
319→      logger.info("Skipping issue close for PR mode", { prNumber: ctx.prNumber });
320→      return transition(ctx, "done");
321→    }
322→    await github.closeIssue(ctx.issueNumber!);
323→    logger.info("Issue closed", { issue: ctx.issueNumber });
324→    return transition(ctx, "done");
325→  };
326→
327→  return {
328→    init,
329→    planning,
330→    implementing,
331→    reviewing,
332→    committing,
333→    creating_pr,
334→    watching_ci,
335→    fixing,
336→    merging,
337→    closing_issue,
338→  };
339→}
340→

