 17→function createFilePersistence(baseDir: string): Persistence {
 18→  return {
 19→    async save(ctx) {
 20→      const dir = join(baseDir, ctx.runId);
 21→      await mkdir(dir, { recursive: true });
 22→      await writeFile(join(dir, "state.json"), JSON.stringify(ctx, null, 2));
 23→
 24→      if (ctx.plan)
 25→        await writeFile(
 26→          join(dir, "plan.json"),
 27→          JSON.stringify(ctx.plan, null, 2)
 28→        );
 29→      if (ctx.result)
 30→        await writeFile(
 31→          join(dir, "result.json"),
 32→          JSON.stringify(ctx.result, null, 2)
 33→        );
 34→      if (ctx.review)
 35→        await writeFile(
 36→          join(dir, "review.json"),
 37→          JSON.stringify(ctx.review, null, 2)
 38→        );
 39→      if (ctx.fix)
 40→        await writeFile(
 41→          join(dir, "fix.json"),
 42→          JSON.stringify(ctx.fix, null, 2)
 43→        );
 44→    },
 45→    async load(runId) {
 46→      try {
 47→        const data = await readFile(
 48→          join(baseDir, runId, "state.json"),
 49→          "utf-8"
 50→        );
 51→        return JSON.parse(data) as RunContext;
 52→      } catch {
 53→        return null;
 54→      }
 55→    },
 56→    async findLatestByIssue(issueNumber) {
 57→      const { readdir } = await import("node:fs/promises");
 58→      let dirs: string[];
 59→      try {
 60→        dirs = await readdir(baseDir);
 61→      } catch {
 62→        return null;
 63→      }
 64→      // Sort descending by timestamp (embedded in dir name)
 65→      dirs.sort().reverse();
 66→      for (const dir of dirs) {
 67→        try {
 68→          const data = await readFile(join(baseDir, dir, "state.json"), "utf-8");
 69→          const ctx = JSON.parse(data) as RunContext;
 70→          if (ctx.issueNumber === issueNumber) return ctx;
 71→        } catch {
 72→          continue;
 73→        }
 74→      }
 75→      return null;
 76→    },
 77→    async findLatestByPr(prNumber) {
 78→      const { readdir } = await import("node:fs/promises");
 79→      let dirs: string[];
 80→      try {
 81→        dirs = await readdir(baseDir);
 82→      } catch {
 83→        return null;
 84→      }
 85→      dirs.sort().reverse();
 86→      for (const dir of dirs) {
 87→        try {
 88→          const data = await readFile(join(baseDir, dir, "state.json"), "utf-8");
 89→          const ctx = JSON.parse(data) as RunContext;
 90→          if (ctx.prNumber === prNumber && ctx.targetKind === "pr") return ctx;
 91→        } catch {
 92→          continue;
 93→        }
 94→      }
 95→      return null;
 96→    },
 97→  };
 98→}
