105→export function createCli() {
106→  const program = new Command();
107→
108→  program.name("aidev").description("AI-powered development loop").version("0.0.1");
109→
110→  const runCmd = program
111→    .command("run")
112→    .description("Run the full dev loop for an issue or pull request")
113→    .option("--issue <number>", "GitHub issue number", parseInt)
114→    .option("--pr <number>", "GitHub pull request number", parseInt)
115→    .option("--cwd <path>", "Working directory", process.cwd())
116→    .option("--max-fix-attempts <n>", "Max CI fix attempts", parseInt, 3)
117→    .option("--dry-run", "Skip push/PR/merge", false)
118→    .option("--auto-merge", "Merge PR and close issue after CI passes", false)
119→    .option("--base <branch>", "Base branch or tag to create branch from", "main")
120→    .option("--repo <owner/name>", "GitHub repo (owner/name)")
121→    .option("--claude-path <path>", "Path to native Claude Code executable")
122→    .option("--resume", "Resume the latest run for this target")
123→    .option("-y, --yes", "Skip interactive confirmation", false)
124→    .option("--allow-foreign-issues", "Allow processing issues or PRs from other users", false);
125→
126→  runCmd.action(async (opts) => {
127→      if (opts.claudePath) process.env.CLAUDE_EXECUTABLE = opts.claudePath;
128→      const logger = createLogger("info");
129→      const baseDir = join(
130→        process.env.HOME ?? "~",
131→        ".devloop",
132→        "runs"
133→      );
134→      const persistence = createFilePersistence(baseDir);
135→      const targetKind = opts.pr != null ? "pr" : "issue";
136→      const targetNumber = targetKind === "pr" ? opts.pr : opts.issue;
137→
138→      if ((opts.issue == null && opts.pr == null) || (opts.issue != null && opts.pr != null)) {
139→        logger.error("Specify exactly one of --issue or --pr");
140→        process.exit(1);
141→      }
142→
143→      let ctx: RunContext;
144→
145→      if (opts.resume) {
146→        const saved =
147→          targetKind === "pr"
148→            ? await persistence.findLatestByPr?.(opts.pr)
149→            : await persistence.findLatestByIssue?.(opts.issue);
150→        if (!saved) {
151→          logger.error("No previous run found for target", { targetKind, targetNumber });
152→          process.exit(1);
153→        }
154→        // Override flags for resumed run
155→        ctx = {
156→          ...saved,
157→          dryRun: opts.dryRun,
158→          autoMerge: opts.autoMerge,
159→        };
160→        // If previous run completed as done (dry-run), restart from creating_pr
161→        // (commit already exists, just need push + PR)
162→        if (saved.state === "done" && saved.dryRun) {
163→          ctx.state = "creating_pr";
164→        }
165→        logger.info("Resuming run", { runId: ctx.runId, fromState: ctx.state, targetKind, targetNumber });
166→      } else {
167→        const runId = `run-${Date.now()}-${randomUUID().slice(0, 8)}`;
168→        const cwd = opts.cwd;
169→        const repo = opts.repo ?? detectRepo(cwd);
170→        const ghForConfirm = createGitHubAdapter(repo);
171→
172→        let issue: Issue | undefined;
173→        let pr: PullRequest | undefined;
174→        let branch: string;
175→
176→        if (targetKind === "pr") {
177→          pr = await ghForConfirm.getPr(opts.pr);
178→          branch = pr.headRefName;
179→        } else {
