181→          branch = `aidev/issue-${opts.issue}`;
182→        }
183→
184→        const target = targetKind === "pr" ? pr! : issue!;
185→
186→        if (!opts.yes) {
187→          if (process.stdin.isTTY) {
188→            const truncated = target.body && target.body.length > 500
189→              ? target.body.slice(0, 500) + "..."
190→              : target.body;
191→            console.log(`\n--- ${targetKind.toUpperCase()} #${target.number}: ${target.title} ---`);
192→            console.log(`Author: ${target.author}`);
193→            if (truncated) console.log(`\n${truncated}\n`);
194→
195→            const confirmed = await new Promise<boolean>((resolve) => {
196→              const rl = createInterface({ input: process.stdin, output: process.stdout });
197→              rl.question("Proceed with this issue? (y/N) ", (answer) => {
198→                rl.close();
199→                resolve(answer.toLowerCase() === "y");
200→              });
201→            });
202→
203→            if (!confirmed) {
204→              logger.info("Cancelled by user");
205→              process.exit(0);
206→            }
207→          } else {
208→            logger.info("Non-interactive mode: skipping confirmation (use --yes to suppress this message)");
209→          }
210→        }
211→
212→        // Track which flags were explicitly set via CLI
213→        const cliExplicit = new Set<string>();
214→        const flagMap: Record<string, string> = {
215→          maxFixAttempts: "max-fix-attempts",
216→          dryRun: "dry-run",
217→          autoMerge: "auto-merge",
218→          base: "base",
219→        };
220→        for (const [ctxKey, cliName] of Object.entries(flagMap)) {
221→          if (runCmd.getOptionValueSource(cliName) === "cli") {
222→            cliExplicit.add(ctxKey);
223→          }
224→        }
225→
226→        ctx = {
227→          runId,
228→          targetKind,
229→          issueNumber: opts.issue,
230→          prNumber: opts.pr,
231→          repo,
232→          cwd,
233→          state: "init",
234→          branch,
235→          headBranch: pr?.headRefName,
236→          base: opts.base,
237→          maxFixAttempts: opts.maxFixAttempts,
238→          fixAttempts: 0,
239→          dryRun: opts.dryRun,
240→          autoMerge: opts.autoMerge,
241→          issueLabels: [],
242→          skipStates: [],
243→          skipAuthorCheck: opts.allowForeignIssues,
244→          _cliExplicit: cliExplicit.size > 0 ? cliExplicit : undefined,
245→        };
246→      }
247→
248→      const git = createGitAdapter();
249→      const github = createGitHubAdapter(ctx.repo);
250→      const handlers = createStateHandlers({ git, github, logger, runDocumenter, loadRepoConfig });
251→
252→      const slackNotify = createSlackNotifier({
253→        webhookUrl: process.env.AIDEV_SLACK_WEBHOOK_URL,
254→        botToken: process.env.AIDEV_SLACK_BOT_TOKEN,
255→        channel: process.env.AIDEV_SLACK_CHANNEL,
256→      });
257→
258→      logger.info("Starting devloop", { runId: ctx.runId, targetKind, targetNumber, repo: ctx.repo });
259→      const workflowStart = performance.now();
260→
261→      const result = await runWorkflow(ctx, handlers, persistence, {
262→        logger,
263→        onTransition: (from, to) =>
264→          logger.info("State transition", { from, to }),
265→        onComplete: async (finalCtx) => {
266→          const elapsedMs = Math.round(performance.now() - workflowStart);
267→          const message = formatSlackMessage({
268→            targetKind: finalCtx.targetKind,
269→            targetNumber: finalCtx.issueNumber ?? finalCtx.prNumber!,
270→            issueTitle: finalCtx.issueTitle,
271→            repo: finalCtx.repo,
272→            finalState: finalCtx.state as "done" | "failed",
273→            elapsedMs,
274→            prNumber: finalCtx.prNumber,
275→          });
276→          await slackNotify(message);
277→        },
278→      });
279→
280→      if (result.state === "done") {
281→        logger.info("Devloop completed successfully", { runId: ctx.runId });
282→      } else {
283→        logger.error("Devloop failed", { runId: ctx.runId, state: result.state });
284→        process.exit(1);
285→      }
286→    });
