  2→import { SkippableStateSchema } from "../types.js";
  3→import type { SkippableState } from "../types.js";
  4→
  5→export type { SkippableState } from "../types.js";
  6→
  7→const IssueConfigSchema = z
  8→  .object({
  9→    maxFixAttempts: z.number().int().positive().optional(),
 10→    autoMerge: z.boolean().optional(),
 11→    dryRun: z.boolean().optional(),
 12→    base: z.string().optional(),
 13→    skip: z.array(SkippableStateSchema).optional(),
 14→  })
 15→  .strict();
 16→
 17→export type IssueConfig = z.infer<typeof IssueConfigSchema>;
 18→
 19→export interface ResolvedConfig {
 20→  maxFixAttempts: number;
 21→  autoMerge: boolean;
 22→  dryRun: boolean;
 23→  base: string;
 24→  skip: SkippableState[];
 25→}
 26→
 27→/**
 28→ * Extract the content inside the first ```aidev ... ``` code fence.
 29→ */
 30→function extractAidevBlock(body: string): string | null {
 31→  const match = body.match(/```aidev\s*\n([\s\S]*?)```/);
 32→  return match?.[1] ?? null;
 33→}
 34→
 35→/**
 36→ * Parse a simple YAML-like block into a raw key-value structure.
 37→ * Supports:
 38→ *   key: value
 39→ *   key:
 40→ *     - item
 41→ *   # comment lines (skipped)
 42→ */
 43→function parseYamlLike(block: string): Record<string, string | string[]> {
 44→  const result: Record<string, string | string[]> = {};
 45→  const lines = block.split("\n");
 46→  let currentKey: string | null = null;
 47→  let currentList: string[] | null = null;
 48→
 49→  for (const rawLine of lines) {
 50→    const line = rawLine.trim();
 51→    if (!line) continue;
 52→    if (line.startsWith("#")) continue;
 53→
 54→    const listItem = line.match(/^-\s+(.+)$/);
