      botToken: process.env.AIDEV_SLACK_BOT_TOKEN,
      channel: process.env.AIDEV_SLACK_CHANNEL,
    });

    logger.info("Starting devloop", {
      runId: ctx.runId,
      targetKind,
      targetNumber,
      repo: ctx.repo,
